CREATE TABLE IF NOT EXISTS admin (                                     admin_id INT PRIMARY KEY AUTO_INCREMENT,                                     admin_email VARCHAR(255) UNIQUE NOT NULL,                                     admin_password_hash VARCHAR(255),                                     admin_role ENUM('restaurant_admin','developer_admin') NOT NULL,                                     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);CREATE TABLE IF NOT EXISTS user ( -- Add an order history references later                                    user_id INT PRIMARY KEY AUTO_INCREMENT,                                    user_email VARCHAR(255) UNIQUE NOT NULL,                                    user_password_hash VARCHAR(255) NOT NULL,                                    user_phone_number INT(10) UNIQUE NULL,                                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);CREATE TABLE IF NOT EXISTS dishes ( -- add a category references later                                      dish_id INT PRIMARY KEY AUTO_INCREMENT,                                      name VARCHAR(255) NOT NULL UNIQUE,                                      description VARCHAR(255) NOT NULL,                                      price DECIMAL(5,2) NOT NULL,                                      dietary_info VARCHAR(255) NULL,                                      spice_level INT NULL,                                      image_url VARCHAR(255) NULL,                                      is_available boolean NOT NULL,                                      created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);